        """Pattern can match and replace the entire filename."""
        files = ["report-2024.pdf"]
        result = compute_renames(files, r"report-(\d+)\.pdf", r"annual_\1.pdf")
        self.assertEqual(result, {"report-2024.pdf": "annual_2024.pdf"})


